import React, { useState } from 'react';

function Navbar() {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <nav className="bg-white shadow-md py-4 px-6 md:px-12 lg:px-24 sticky top-0 z-50">
      <div className="container mx-auto flex justify-between items-center">
        <div className="text-2xl font-bold text-indigo-700">
          MyBrand
        </div>
        <div className="hidden md:flex space-x-8">
          <a href="#features" className="text-gray-700 hover:text-indigo-600 transition duration-300 ease-in-out">Features</a>
          <a href="#testimonials" className="text-gray-700 hover:text-indigo-600 transition duration-300 ease-in-out">Testimonials</a>
          <a href="#contact" className="text-gray-700 hover:text-indigo-600 transition duration-300 ease-in-out">Contact</a>
        </div>
        <div className="md:hidden">
          <button onClick={() => setIsOpen(!isOpen)} className="text-gray-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 rounded-md p-2" aria-label="Toggle navigation">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={isOpen ? "M6 18L18 6M6 6l12 12" : "M4 6h16M4 12h16M4 18h16"}></path>
            </svg>
          </button>
        </div>
      </div>
      {isOpen && (
        <div className="md:hidden mt-4 space-y-2 bg-white rounded-lg shadow-lg py-4 px-6">
          <a href="#features" className="block text-gray-700 hover:text-indigo-600 transition duration-300 ease-in-out py-2">Features</a>
          <a href="#testimonials" className="block text-gray-700 hover:text-indigo-600 transition duration-300 ease-in-out py-2">Testimonials</a>
          <a href="#contact" className="block text-gray-700 hover:text-indigo-600 transition duration-300 ease-in-out py-2">Contact</a>
        </div>
      )}
    </nav>
  );
}

export default Navbar;

